#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void solve(vector<vector<int>>& tree) {
        int n = tree.size();
        vector<int> pre, ino, post;
        vector<pair<int, bool>> stk = {{0, false}};
        while (!stk.empty()) {
            int i = stk.back().first;
            bool visited = stk.back().second;
            stk.pop_back();
            if (i == -1) {
                continue;
            }
            if (visited) {
                ino.push_back(tree[i][0]);
                post.push_back(tree[i][0]);
            } else {
                pre.push_back(tree[i][0]);
                stk.push_back({i, true});
                stk.push_back({tree[i][2], false});
                stk.push_back({tree[i][1], false});
            }
        }
        for (int x : pre) cout << x << " ";
        cout << "\n";
        for (int x : ino) cout << x << " ";
        cout << "\n";
        for (int x : post) cout << x << " ";
        cout << "\n";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<vector<int>> tree(n);
    for (int i = 0; i < n; i++) {
        tree[i].resize(3);
        cin >> tree[i][0] >> tree[i][1] >> tree[i][2];
    }
    Solution sol;
    sol.solve(tree);
    return 0;
}
